static const double W10_1_re = 8.09016994374947451263e-01;
static const double W10_1_im = -5.87785252292473137103e-01;
static const double W10_2_re = 3.09016994374947451263e-01;
static const double W10_2_im = -9.51056516295153531182e-01;
static const double W10_3_re = -3.09016994374947340241e-01;
static const double W10_3_im = -9.51056516295153642204e-01;
static const double W10_4_re = -8.09016994374947340241e-01;
static const double W10_4_im = -5.87785252292473248126e-01;
