          __m512d c_=LD(&tbuf_re[2*8]), d_=LD(&tbuf_re[3*8]);
          out_re[(k+0)*ovs+os*0] = tbuf_re[0*8+0];
          out_re[(k+0)*ovs+os*1] = tbuf_re[1*8+0];
          out_re[(k+0)*ovs+os*2] = tbuf_re[2*8+0];
